import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");

        // Properly encode user input to prevent XSS
        try {
            String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);
            out.println("<h1>Welcome " + encodedUserInput + "!</h1>");
        } catch (EncodingException e) {
            out.println("<h1>Welcome Guest!</h1>"); // Handle encoding exception gracefully
        }

        out.println("</body>");
        out.println("</html>");
    }
}

